21	// ExecResult holds the raw output of a command execution.
22	type ExecResult struct {
23		Stdout           string
24		Stderr           string
25		ExitCode         int
26		EarlyCancel      bool          // true if execution was cancelled due to detected auth/rate-limit error
27		CancelReason     string        // the matched pattern that caused early cancellation
28		WallClockTimeout bool          // true if the absolute wall-clock deadline fired (vs the resettable idle timer)
29		WallClockElapsed time.Duration // how long the process ran before the wall-clock timer fired; zero when WallClockTimeout is false
30	}
31	
32	// Executor abstracts command execution for testability.
33	type Executor interface {
34		Execute(ctx context.Context, binary string, args []string, stdin string) (*ExecResult, error)
35		// ExecuteInDir runs the command in the specified directory.
36		// Falls back to Execute if dir is empty.
37		ExecuteInDir(ctx context.Context, binary string, args []string, stdin, dir string) (*ExecResult, error)
38	}
