40	type executionTimeoutKey struct{}
41	
42	func withExecutionTimeout(ctx context.Context, timeout time.Duration) context.Context {
43		if timeout <= 0 {
44			return ctx
45		}
46		return context.WithValue(ctx, executionTimeoutKey{}, timeout)
47	}
48	
49	func executionTimeoutFromContext(ctx context.Context) time.Duration {
50		if ctx == nil {
51			return 0
52		}
53		if timeout, ok := ctx.Value(executionTimeoutKey{}).(time.Duration); ok {
54			return timeout
55		}
56		return 0
57	}
