90	func executionEnvFromContext(ctx context.Context) map[string]string {
91		if ctx == nil {
92			return nil
93		}
94		env, ok := ctx.Value(executionEnvKey{}).(map[string]string)
95		if !ok || len(env) == 0 {
96			return nil
97		}
98		return cloneStringMap(env)
99	}
