13	const (
14		executionResourceMinFreeBytes  uint64 = 64 << 20
15		executionResourceMinFreeInodes uint64 = 1024
16	
17		executionResourceSoftMinFreeBytes  uint64 = 512 << 20
18		executionResourceSoftMinFreeInodes uint64 = 4096
19	)
20	
21	// ExecutionResourceRootCheck captures the health of one execution root.
22	type ExecutionResourceRootCheck struct {
23		Path           string   `json:"path"`
24		Writable       bool     `json:"writable"`
25		WritableReason string   `json:"writable_reason,omitempty"`
26		BytesFree      uint64   `json:"bytes_free,omitempty"`
27		InodesFree     uint64   `json:"inodes_free,omitempty"`
28		Notes          []string `json:"notes,omitempty"`
29	}
30	
31	// ExecutionResourceCheckResult captures the roots and cleanup summary observed
32	// during one resource preflight.
33	type ExecutionResourceCheckResult struct {
34		ProjectRoot      string                       `json:"project_root"`
35		TempRoot         string                       `json:"temp_root"`
36		EvidenceRoots    []string                     `json:"evidence_roots,omitempty"`
37		BeforeRootChecks []ExecutionResourceRootCheck `json:"before_root_checks,omitempty"`
38		RootChecks       []ExecutionResourceRootCheck `json:"root_checks,omitempty"`
39		CleanupSummary   ExecutionCleanupSummary      `json:"cleanup_summary,omitempty"`
40	}
41	
42	// ResourceExhaustedError signals that execution roots remained unhealthy after
43	// a cleanup retry. The caller should stop claiming new work.
44	type ResourceExhaustedError struct {
45		Detail string
46		Result ExecutionResourceCheckResult
47	}
48	
49	func (e *ResourceExhaustedError) Error() string {
50		if e == nil {
51			return "resource_exhausted"
52		}
53		if strings.TrimSpace(e.Detail) == "" {
54			return "resource_exhausted"
55		}
56		return "resource_exhausted: " + e.Detail
57	}
58	
59	type executionCleanupRunner interface {
60		Cleanup(ctx context.Context) (ExecutionCleanupSummary, error)
61	}
62	
63	// ExecutionResourceChecker validates DDx execution roots before claim or
64	// worktree creation. It is safe for tests to override RootProbe and
65	// CleanupRunner to simulate low-space or cleanup-recovery scenarios.
66	type ExecutionResourceChecker interface {
67		Check(ctx context.Context) (ExecutionResourceCheckResult, error)
68	}
69	
70	// ExecutionResourcePreflight is the default checker used by ddx try/work.
71	type ExecutionResourcePreflight struct {
72		ProjectRoot   string
73		TempRoot      string
74		EvidenceRoots []string
75		GitOps        GitOps
76	
77		// SoftMin* triggers a cleanup pass before claims when free capacity drops
78		// below the soft floor. HardMin* is the stop floor after cleanup.
79		SoftMinFreeBytes  uint64
80		SoftMinFreeInodes uint64
81		HardMinFreeBytes  uint64
82		HardMinFreeInodes uint64
83	
84		CleanupRunner executionCleanupRunner
85		RootProbe     func(path string) (ExecutionResourceRootCheck, error)
86	}
87	
88	// NewExecutionResourceChecker constructs the default preflight checker.
89	func NewExecutionResourceChecker(projectRoot string, gitOps GitOps) *ExecutionResourcePreflight {
90		return &ExecutionResourcePreflight{
91			ProjectRoot: projectRoot,
92			TempRoot:    executionCleanupTempRoot(projectRoot),
93			EvidenceRoots: []string{
94				executeBeadArtifactRoot(projectRoot), ddxroot.JoinProject(projectRoot, "runs"),
95			},
96			GitOps:        gitOps,
97			CleanupRunner: NewExecutionCleanupManager(projectRoot, gitOps),
98			RootProbe:     probeExecutionRoot,
99		}
100	}
101	
102	func (p *ExecutionResourcePreflight) Check(ctx context.Context) (ExecutionResourceCheckResult, error) {
103		if ctx == nil {
104			ctx = context.Background()
105		}
106		if p == nil {
107			return ExecutionResourceCheckResult{}, nil
108		}
109	
110		result := ExecutionResourceCheckResult{
111			ProjectRoot:   p.projectRoot(),
112			TempRoot:      p.tempRoot(),
113			EvidenceRoots: p.evidenceRoots(),
114		}
115	
116		checks, detail, healthy, softDetail, softHealthy := p.checkRoots()
117		result.RootChecks = checks
118		if healthy && softHealthy {
119			return result, nil
120		}
121		if detail == "" {
122			detail = softDetail
123		}
124		result.BeforeRootChecks = append([]ExecutionResourceRootCheck(nil), checks...)
125	
126		if p.CleanupRunner != nil {
127			summary, cleanupErr := p.CleanupRunner.Cleanup(ctx)
128			result.CleanupSummary = summary
129			if cleanupErr != nil {
130				if detail != "" {
131					detail += "; "
132				}
133				detail += "cleanup: " + cleanupErr.Error()
134			}
135		}
136	
137		checks, recheckDetail, recheckHealthy, _, _ := p.checkRoots()
138		result.RootChecks = checks
139		if recheckHealthy {
140			return result, nil
141		}
142		if recheckDetail != "" {
143			detail = recheckDetail
144		}
145		return result, &ResourceExhaustedError{Detail: detail, Result: result}
146	}
147	
148	func (p *ExecutionResourcePreflight) projectRoot() string {
149		if p == nil {
150			return ""
151		}
152		return p.ProjectRoot
153	}
154	
155	func (p *ExecutionResourcePreflight) tempRoot() string {
156		if p == nil {
157			return executionCleanupTempRoot("")
158		}
159		if p.TempRoot != "" {
160			return p.TempRoot
161		}
162		return executionCleanupTempRoot(p.ProjectRoot)
163	}
164	
165	func (p *ExecutionResourcePreflight) evidenceRoots() []string {
166		if p == nil || len(p.EvidenceRoots) == 0 {
167			return nil
168		}
169		return append([]string(nil), p.EvidenceRoots...)
170	}
171	
172	func (p *ExecutionResourcePreflight) allRoots() []string {
173		roots := []string{p.tempRoot()}
174		roots = append(roots, p.evidenceRoots()...)
175		return roots
176	}
177	
178	func (p *ExecutionResourcePreflight) checkRoots() ([]ExecutionResourceRootCheck, string, bool, string, bool) {
179		roots := p.allRoots()
180		checks := make([]ExecutionResourceRootCheck, 0, len(roots))
181		var details, softDetails []string
182		healthy := true
183		softHealthy := true
184		for _, root := range roots {
185			check, err := p.checkRoot(root)
186			if err != nil {
187				healthy = false
188				details = append(details, err.Error())
189			} else if softNotes := p.softPressureNotes(check); len(softNotes) > 0 {
190				softHealthy = false
191				check.Notes = append(check.Notes, softNotes...)
192				for _, note := range softNotes {
193					softDetails = append(softDetails, fmt.Sprintf("resource preflight: %s: %s", root, note))
194				}
195			}
196			checks = append(checks, check)
197		}
198		return checks, strings.Join(details, "; "), healthy, strings.Join(softDetails, "; "), softHealthy
199	}
200	
201	func (p *ExecutionResourcePreflight) checkRoot(root string) (ExecutionResourceRootCheck, error) {
202		check := ExecutionResourceRootCheck{Path: root}
203		if strings.TrimSpace(root) == "" {
204			check.Notes = append(check.Notes, "empty root")
205			return check, fmt.Errorf("resource preflight: empty root")
206		}
207		if err := os.MkdirAll(root, 0o755); err != nil {
208			check.Notes = append(check.Notes, "mkdir: "+err.Error())
209			return check, fmt.Errorf("resource preflight: %s: mkdir: %w", root, err)
210		}
211	
212		writable, writableReason := probeWritableRoot(root)
213		check.Writable = writable
214		check.WritableReason = writableReason
215		if !writable {
216			check.Notes = append(check.Notes, writableReason)
217			return check, fmt.Errorf("resource preflight: %s: %s", root, writableReason)
218		}
219	
220		if p.RootProbe != nil {
221			probed, err := p.RootProbe(root)
222			if err != nil {
223				check.Notes = append(check.Notes, err.Error())
224				return check, err
225			}
226			check.BytesFree = probed.BytesFree
227			check.InodesFree = probed.InodesFree
228			check.Notes = append(check.Notes, probed.Notes...)
229			if !probed.Writable {
230				msg := probed.WritableReason
231				if msg == "" {
232					msg = "root probe reported unwritable"
233				}
234				check.Notes = append(check.Notes, msg)
235				return check, fmt.Errorf("resource preflight: %s: %s", root, msg)
236			}
237			if probed.BytesFree > 0 && probed.BytesFree < p.hardMinFreeBytes() {
238				msg := fmt.Sprintf("free bytes %d < required %d", probed.BytesFree, p.hardMinFreeBytes())
239				check.Notes = append(check.Notes, msg)
240				return check, fmt.Errorf("resource preflight: %s: %s", root, msg)
241			}
242			if probed.InodesFree > 0 && probed.InodesFree < p.hardMinFreeInodes() {
243				msg := fmt.Sprintf("free inodes %d < required %d", probed.InodesFree, p.hardMinFreeInodes())
244				check.Notes = append(check.Notes, msg)
245				return check, fmt.Errorf("resource preflight: %s: %s", root, msg)
246			}
247			return check, nil
248		}
249	
250		bytesFree, inodesFree, err := probeRootCapacity(root)
251		if err != nil {
252			check.Notes = append(check.Notes, err.Error())
253			return check, err
254		}
255		check.BytesFree = bytesFree
256		check.InodesFree = inodesFree
257		if bytesFree > 0 && bytesFree < p.hardMinFreeBytes() {
258			msg := fmt.Sprintf("free bytes %d < required %d", bytesFree, p.hardMinFreeBytes())
259			check.Notes = append(check.Notes, msg)
260			return check, fmt.Errorf("resource preflight: %s: %s", root, msg)
261		}
262		if inodesFree > 0 && inodesFree < p.hardMinFreeInodes() {
263			msg := fmt.Sprintf("free inodes %d < required %d", inodesFree, p.hardMinFreeInodes())
264			check.Notes = append(check.Notes, msg)
265			return check, fmt.Errorf("resource preflight: %s: %s", root, msg)
266		}
267		return check, nil
268	}
269	
270	func (p *ExecutionResourcePreflight) softPressureNotes(check ExecutionResourceRootCheck) []string {
271		var notes []string
272		if min := p.softMinFreeBytes(); min > 0 && check.BytesFree > 0 && check.BytesFree < min {
273			notes = append(notes, fmt.Sprintf("free bytes %d < soft cleanup threshold %d", check.BytesFree, min))
274		}
275		if min := p.softMinFreeInodes(); min > 0 && check.InodesFree > 0 && check.InodesFree < min {
