309	func probeWritableRoot(root string) (bool, string) {
310		f, err := os.CreateTemp(root, ".ddx-resource-preflight-*")
311		if err != nil {
312			return false, "writability check failed: " + err.Error()
313		}
314		name := f.Name()
315		if closeErr := f.Close(); closeErr != nil {
316			_ = os.Remove(name)
317			return false, "writability check close failed: " + closeErr.Error()
318		}
319		if removeErr := os.Remove(name); removeErr != nil {
320			return false, "writability check remove failed: " + removeErr.Error()
321		}
322		return true, ""
323	}
