325	func probeExecutionRoot(root string) (ExecutionResourceRootCheck, error) {
326		check := ExecutionResourceRootCheck{Path: root}
327		writable, writableReason := probeWritableRoot(root)
328		check.Writable = writable
329		check.WritableReason = writableReason
330		if !writable {
331			return check, fmt.Errorf("resource preflight: %s: %s", root, writableReason)
332		}
333		bytesFree, inodesFree, err := probeRootCapacity(root)
334		if err != nil {
335			return check, fmt.Errorf("resource preflight: %s: %w", root, err)
336		}
337		check.BytesFree = bytesFree
338		check.InodesFree = inodesFree
339		return check, nil
340	}
