342	func probeRootCapacity(root string) (bytesFree uint64, inodesFree uint64, err error) {
343		var stat unix.Statfs_t
344		if err := unix.Statfs(root, &stat); err != nil {
345			return 0, 0, fmt.Errorf("statfs %s: %w", root, err)
346		}
347		bytesFree = uint64(stat.Bavail) * uint64(stat.Bsize)
348		inodesFree = uint64(stat.Ffree)
349		return bytesFree, inodesFree, nil
350	}
