34	func nextEscalationFloor(l escalationFloorFinder, actualPower int) (int, error) {
35		if l == nil {
36			return 0, powerladder.ErrLadderExhausted
37		}
38		floor := actualPower
39		for {
40			next, err := l.Next(floor)
41			if err == nil {
42				return next, nil
43			}
44			var nvp *powerladder.NoViableProviderError
45			if errors.As(err, &nvp) {
46				floor = nvp.Floor
47				continue
48			}
49			return 0, err
50		}
51	}
52	
53	func highestViableEscalationFloor(l escalationFloorFinder) (int, error) {
54		if l == nil {
55			return 0, powerladder.ErrLadderExhausted
56		}
57		floor := 0
58		highest := 0
59		for {
60			next, err := nextEscalationFloor(l, floor)
61			if err != nil {
62				if errors.Is(err, powerladder.ErrLadderExhausted) && highest > 0 {
63					return highest, nil
64				}
65				return 0, err
66			}
67			highest = next
68			floor = next
69		}
70	}
