76	func recentProviderConnectivityMinPower(store *bead.Store, now time.Time, baseMinPower, maxPower int, ladder escalationFloorFinder) (int, agent.ExecuteBeadReport, bool) {
77		if store == nil || ladder == nil {
78			return baseMinPower, agent.ExecuteBeadReport{}, false
79		}
80		beads, err := store.List("", "", nil)
81		if err != nil {
82			return baseMinPower, agent.ExecuteBeadReport{}, false
83		}
84		floor := baseMinPower
85		for _, b := range beads {
86			events, err := store.Events(b.ID)
87			if err != nil {
88				continue
89			}
90			if next, ok := recentProviderConnectivityMinPowerFromEvents(events, now, floor, maxPower, ladder); ok {
91				if next >= maxPower && maxPower > 0 {
92					return baseMinPower, routeUnavailableReport(&b, next, maxPower, nil), true
93				}
94				if next > floor {
95					floor = next
96				}
97			}
98		}
99		if floor > baseMinPower {
100			return floor, agent.ExecuteBeadReport{}, true
101		}
102		return baseMinPower, agent.ExecuteBeadReport{}, false
103	}
