105	func recentProviderConnectivityMinPowerFromEvents(events []bead.BeadEvent, now time.Time, baseMinPower, maxPower int, ladder escalationFloorFinder) (int, bool) {
106		if len(events) == 0 || ladder == nil {
107			return baseMinPower, false
108		}
109		floor := baseMinPower
110		var last recentRouteEvent
111		for _, ev := range events {
112			if ev.CreatedAt.IsZero() || now.Sub(ev.CreatedAt) > agent.ProviderUnavailableCooldown || ev.CreatedAt.After(now.Add(time.Minute)) {
113				continue
114			}
115			if route, ok := routeEventFromBeadEvent(ev); ok {
116				last = route
117				continue
118			}
119			if ev.Kind == "route-failure" {
120				route, ok := routeFailureEventFromBeadEvent(ev)
121				if !ok {
122					continue
123				}
124				if next, ok := nextFloorForRecentConnectivity(route.ActualPower, maxPower, ladder); ok && next > floor {
125					floor = next
126				}
127				continue
128			}
129			if ev.Kind == "execute-bead" && strings.EqualFold(strings.TrimSpace(ev.Summary), "execution_failed") && isProviderConnectivityEventBody(ev.Body) && last.Provider != "" {
130				if next, ok := nextFloorForRecentConnectivity(last.ActualPower, maxPower, ladder); ok && next > floor {
131					floor = next
132				}
133			}
134		}
135		return floor, floor > baseMinPower
136	}
