144	func routeEventFromBeadEvent(ev bead.BeadEvent) (recentRouteEvent, bool) {
145		if ev.Kind != "routing" && ev.Kind != "execution-routing-intent" {
146			return recentRouteEvent{}, false
147		}
148		var body map[string]any
149		if err := json.Unmarshal([]byte(ev.Body), &body); err != nil {
150			return recentRouteEvent{}, false
151		}
152		route := recentRouteEvent{
153			Provider:    firstNonEmptyString(body["resolved_provider"], body["actual_provider"], body["provider"]),
154			Model:       firstNonEmptyString(body["resolved_model"], body["actual_model"], body["model"]),
155			ActualPower: intFromAny(body["actual_power"]),
156		}
157		if route.Provider == "" {
158			return recentRouteEvent{}, false
159		}
160		return route, true
161	}
