163	func routeFailureEventFromBeadEvent(ev bead.BeadEvent) (recentRouteEvent, bool) {
164		var body map[string]any
165		if err := json.Unmarshal([]byte(ev.Body), &body); err != nil {
166			return recentRouteEvent{}, false
167		}
168		if reason := strings.TrimSpace(fmt.Sprint(body["outcome_reason"])); reason != "" && reason != agent.FailureModeProviderConnectivity {
169			return recentRouteEvent{}, false
170		}
171		route := recentRouteEvent{
172			Provider:    firstNonEmptyString(body["provider"]),
173			Model:       firstNonEmptyString(body["model"]),
174			ActualPower: intFromAny(body["actual_power"]),
175		}
176		if route.Provider == "" {
177			return recentRouteEvent{}, false
178		}
179		return route, true
180	}
