193	func isProviderConnectivityEventBody(body string) bool {
194		lower := strings.ToLower(body)
195		for _, marker := range []string{"dial tcp", "i/o timeout", "connection refused", "connection reset", "no route to host", "provider error"} {
196			if strings.Contains(lower, marker) {
