212	func intFromAny(value any) int {
213		switch v := value.(type) {
214		case int:
215			return v
216		case int64:
217			return int(v)
218		case float64:
219			return int(v)
220		case json.Number:
221			i, _ := v.Int64()
222			return int(i)
223		default:
224			return 0
225		}
226	}
