228	func resolvePowerFloor(powerClass policyescalation.PowerClass, ladder escalationFloorFinder) (int, bool) {
229		switch powerClass {
230		case policyescalation.PowerSmart:
231			floor, err := highestViableEscalationFloor(ladder)
232			if err != nil {
233				return 0, false
234			}
235			return floor, true
236		case policyescalation.PowerStandard:
237			first, err := nextEscalationFloor(ladder, 0)
238			if err != nil {
239				return 0, false
240			}
241			second, err := nextEscalationFloor(ladder, first)
242			if err != nil {
243				return first, true
244			}
245			return second, true
246		default:
247			return 0, false
248		}
249	}
