251	func zeroConfigInitialMinPower(b *bead.Bead, powerClass policyescalation.PowerClass, baseMinPower, maxPower int, ladder escalationFloorFinder) (int, agent.ExecuteBeadReport, bool) {
252		if powerClass == "" {
253			return baseMinPower, agent.ExecuteBeadReport{}, false
254		}
255		powerFloor, hasPowerFloor := resolvePowerFloor(powerClass, ladder)
256		if !hasPowerFloor && powerClass != policyescalation.PowerCheap {
257			return baseMinPower, routeUnavailableReport(b, baseMinPower, maxPower, fmt.Errorf("no viable routing floor for inferred powerClass %s", powerClass)), true
258		}
259		if powerFloor > baseMinPower {
260			if maxPower > 0 && powerFloor >= maxPower {
261				return baseMinPower, routeUnavailableReport(b, powerFloor, maxPower, nil), true
262			}
263			return powerFloor, agent.ExecuteBeadReport{}, false
264		}
265		return baseMinPower, agent.ExecuteBeadReport{}, false
266	}
