288	func runEscalatingPowerAttempts(
289		ctx context.Context,
290		initialMinPower int,
291		ladder escalationFloorFinder,
292		attempt func(context.Context, int) (agent.ExecuteBeadReport, error),
293		recordAttempt func(agent.ExecuteBeadReport),
294		perBeadTracker *policyescalation.PerBeadCostTracker,
295		allowInfrastructureRetry bool,
296	) (agent.ExecuteBeadReport, error) {
297		minPower := initialMinPower
298		floors := tryLoopFloorFinder{ladder: ladder}
299		for {
300			report, err := attempt(ctx, minPower)
301			if recordAttempt != nil && report.BeadID != "" {
302				recordAttempt(report)
303			}
304			if perBeadTracker != nil {
305				perBeadTracker.Add(report.Harness, report.CostUSD)
306			}
307			if err != nil {
308				return report, err
309			}
310			if perBeadTracker != nil {
311				if detail, tripped := perBeadTracker.Tripped(); tripped {
312					report.Status = agent.ExecuteBeadStatusExecutionFailed
313					report.Detail = detail
314					report.CostUSD = perBeadTracker.Spent()
315					return report, nil
316				}
317			}
