9	// TryLoopState names the in-memory states used while ddx try/work evaluates a
10	// single bead attempt. Persisted bead lifecycle remains the six statuses owned
11	// by TD-027; these states are control-flow states only.
12	type TryLoopState string
13	
14	const (
15		TryLoopStateClassifyResult TryLoopState = "classify_result"
16		TryLoopStateRetryPower     TryLoopState = "retry_power"
17		TryLoopStateStopAttempt    TryLoopState = "stop_attempt"
18	)
19	
20	// TryLoopAction is the action selected by the attempt state machine.
21	type TryLoopAction string
22	
23	const (
24		TryLoopActionStop       TryLoopAction = "stop"
25		TryLoopActionRetryPower TryLoopAction = "retry_power"
26	)
27	
28	// FloorFinder returns the next viable MinPower floor above the supplied power.
29	type FloorFinder interface {
30		Next(actualPower int) (int, error)
31	}
32	
33	// AttemptTransitionInput is the complete input the try-loop state machine needs
34	// to decide whether another implementation attempt is useful.
35	type AttemptTransitionInput struct {
36		Status          string
37		Detail          string
38		CurrentMinPower int
39		ActualPower     int
40	
41		Disrupted                bool
42		BudgetExhausted          bool
43		AllowInfrastructureRetry bool
44	}
45	
46	// AttemptTransition is the state-machine decision for one completed attempt.
47	type AttemptTransition struct {
48		State        TryLoopState
49		Action       TryLoopAction
50		NextMinPower int
51		Reason       string
52	}
53	
54	// DecideAttemptTransition implements the ddx try retry state machine for one
55	// attempt result. The default bias is forward progress: semantic failures move
56	// up the model-power ladder, while retryable provider-connectivity failures can
57	// be retried immediately with MinPower set just above the failed route's actual
58	// power. Infrastructure failures without concrete route evidence still stop the
59	// current attempt; a smarter model cannot fix an absent service with no
60	// alternate power signal.
61	func DecideAttemptTransition(input AttemptTransitionInput, ladder FloorFinder) AttemptTransition {
62		if input.Disrupted {
63			return stopTransition("disrupted")
64		}
65		if input.BudgetExhausted {
66			return stopTransition("budget_exhausted")
67		}
68		if !escalation.ShouldEscalate(input.Status) {
69			return stopTransition("terminal_status")
70		}
71	
72		if escalation.IsInfrastructureFailure(input.Status, input.Detail) {
73			if !input.AllowInfrastructureRetry || input.ActualPower <= 0 || !isProviderConnectivityDetail(input.Detail) {
74				return stopTransition("infrastructure_no_retry_route")
75			}
76			next := input.ActualPower + 1
77			if next <= input.CurrentMinPower {
78				next = input.CurrentMinPower + 1
79			}
80			return AttemptTransition{
81				State:        TryLoopStateRetryPower,
82				Action:       TryLoopActionRetryPower,
83				NextMinPower: next,
84				Reason:       "infrastructure_retry_with_higher_min_power",
85			}
86		}
87	
88		basis := input.CurrentMinPower
89		if input.ActualPower > 0 {
90			basis = input.ActualPower
91		}
92		next, err := nextLadderFloor(ladder, basis)
93		if err != nil {
94			return stopTransition("power_ladder_exhausted")
95		}
96		return AttemptTransition{
97			State:        TryLoopStateRetryPower,
98			Action:       TryLoopActionRetryPower,
99			NextMinPower: next,
100			Reason:       "semantic_retry_with_higher_min_power",
101		}
102	}
103	
104	func stopTransition(reason string) AttemptTransition {
105		return AttemptTransition{
106			State:  TryLoopStateStopAttempt,
107			Action: TryLoopActionStop,
108			Reason: reason,
109		}
110	}
111	
112	func nextLadderFloor(ladder FloorFinder, basis int) (int, error) {
113		if ladder == nil {
114			return 0, errNoFloorFinder{}
115		}
116		return ladder.Next(basis)
117	}
118	
119	type errNoFloorFinder struct{}
120	
121	func (errNoFloorFinder) Error() string { return "no floor finder configured" }
122	
123	func isProviderConnectivityDetail(detail string) bool {
124		lower := strings.ToLower(detail)
125		for _, marker := range []string{"provider_connectivity", "connection refused", "no route to host", "network is unreachable", "i/o timeout", "connection reset", "dial tcp"} {
126			if strings.Contains(lower, marker) {
127				return true
128			}
129		}
130		return false
131	}
