342	func (InTreeAttemptBackend) Prepare(ctx context.Context, req AttemptBackendPrepareRequest) (*AttemptWorkspace, error) {
343		if err := checkTreeClean(ctx, req.ProjectRoot, req.BeadID); err != nil {
344			return nil, fmt.Errorf("in-tree backend requires clean working tree before claim: %w", err)
345		}
346	
347		lockPath := executeBeadInTreeLockPath(req.ProjectRoot, req.BeadID)
348		if err := os.MkdirAll(filepath.Dir(lockPath), 0o755); err != nil {
349			return nil, fmt.Errorf("creating in-tree lock parent dir: %w", err)
350		}
351	
352		lockFile, err := os.OpenFile(lockPath, os.O_CREATE|os.O_WRONLY|os.O_TRUNC, 0o600)
353		if err != nil {
354			return nil, fmt.Errorf("opening in-tree lock file: %w", err)
355		}
356	
357		if err := acquireExclusiveLock(lockFile); err != nil {
358			lockFile.Close()
359			return nil, fmt.Errorf("in-tree attempt already running for this bead (worker lock held by another process): %w", err)
360		}
361	
362		_, _ = fmt.Fprintf(lockFile, "%d\n", os.Getpid())
363		_ = lockFile.Sync()
364	
365		return &AttemptWorkspace{
366			Backend:        AttemptBackendInTree,
367			ProjectRoot:    req.ProjectRoot,
368			WorkDir:        req.ProjectRoot,
369			BeadID:         req.BeadID,
370			AttemptID:      req.AttemptID,
371			BaseRev:        req.BaseRev,
372			gitOps:         req.GitOps,
373			inTreeLockFile: lockFile,
374		}, nil
375	}
