645	func dockerProjectDockerfile(projectRoot string, cfg *config.ExecutionsDockerConfig) (string, bool, error) {
646		configured := ""
647		if cfg != nil {
648			configured = strings.TrimSpace(cfg.ProjectDockerfile)
649		}
650		if configured == "" {
651			defaultPath := ddxroot.InTree(projectRoot, "attempt-runner.Dockerfile")
652			info, err := os.Stat(defaultPath)
653			if err != nil {
654				if os.IsNotExist(err) {
655					return "", false, nil
656				}
657				return "", false, err
658			}
659			if info.IsDir() {
660				return "", false, fmt.Errorf("docker project dockerfile is a directory: %s", defaultPath)
661			}
662			return defaultPath, true, nil
663		}
664		path, err := projectBoundPath(projectRoot, configured)
665		if err != nil {
666			return "", false, fmt.Errorf("docker project dockerfile: %w", err)
667		}
668		info, err := os.Stat(path)
669		if err != nil {
670			return "", false, fmt.Errorf("docker project dockerfile %s: %w", path, err)
671		}
672		if info.IsDir() {
673			return "", false, fmt.Errorf("docker project dockerfile is a directory: %s", path)
674		}
675		return path, true, nil
676	}
