678	func dockerProjectContext(projectRoot string, cfg *config.ExecutionsDockerConfig) (string, error) {
679		configured := ""
680		if cfg != nil {
681			configured = strings.TrimSpace(cfg.ProjectContext)
682		}
683		if configured == "" {
684			return projectRoot, nil
685		}
686		path, err := projectBoundPath(projectRoot, configured)
687		if err != nil {
688			return "", fmt.Errorf("docker project context: %w", err)
689		}
690		info, err := os.Stat(path)
691		if err != nil {
692			return "", fmt.Errorf("docker project context %s: %w", path, err)
693		}
694		if !info.IsDir() {
695			return "", fmt.Errorf("docker project context is not a directory: %s", path)
696		}
697		return path, nil
698	}
699	
700	func projectBoundPath(projectRoot, path string) (string, error) {
701		if strings.TrimSpace(path) == "" {
702			return "", fmt.Errorf("path is empty")
703		}
704		if !filepath.IsAbs(path) {
705			path = filepath.Join(projectRoot, filepath.FromSlash(path))
706		}
707		cleanRoot := filepath.Clean(projectRoot)
708		cleanPath := filepath.Clean(path)
709		rel, err := filepath.Rel(cleanRoot, cleanPath)
710		if err != nil {
711			return "", err
712		}
713		if rel == ".." || strings.HasPrefix(rel, ".."+string(filepath.Separator)) {
714			return "", fmt.Errorf("path escapes project root: %s", path)
715		}
716		return cleanPath, nil
717	}
