724	func dockerRunArgs(cfg *config.ExecutionsDockerConfig, ws *AttemptWorkspace, exe, image string, tools []dockerToolMount) []string {
725		name := dockerContainerName(ws)
726		args := []string{
727			"run", "--rm", "--init",
728			"--name", name,
729			"--label", "ddx.backend=docker-clone",
730			"--label", "ddx.attempt=" + ws.AttemptID,
731			"--label", "ddx.project=" + shortPathHash(ws.ProjectRoot),
732			"--user", fmt.Sprintf("%d:%d", os.Getuid(), os.Getgid()),
733			"--workdir", "/work",
734			"--mount", "type=bind,src=" + ws.WorkDir + ",dst=/work",
735			"--mount", "type=bind,src=" + exe + ",dst=/usr/local/bin/ddx,readonly",
736			"-e", "PATH=/usr/local/go/bin:/opt/go/bin:/usr/local/bin:/usr/bin:/bin",
737			"-e", "HOME=/ddx-runtime/home",
738			"-e", "XDG_CACHE_HOME=/ddx-runtime/cache",
739			"-e", "TMPDIR=/ddx-runtime/tmp",
740			"-e", "GOCACHE=/work/.gocache",
741			"-e", "GOTMPDIR=/ddx-runtime/go-tmp",
742			"-e", "DDX_PROJECT_ROOT=/work",
743			"-e", DDXModeEnvKey + "=" + DDXModeBeadExecution,
744			"-e", "DDX_BEAD_ID=" + ws.BeadID,
745			"-e", "DDX_ATTEMPT_ID=" + ws.AttemptID,
746		}
747		if ws.DockerRun != "" {
748			args = append(args, "--mount", "type=bind,src="+ws.DockerRun+",dst=/ddx-runtime")
749			gocacheSrc := filepath.Join(ws.DockerRun, "work-gocache")
750			if ws.DockerSharedGoCache != "" {
751				gocacheSrc = ws.DockerSharedGoCache
752			}
753			args = append(args, "--mount", "type=bind,src="+gocacheSrc+",dst=/work/.gocache")
754			args = append(args, "--mount", "type=bind,src="+filepath.Join(ws.DockerRun, "work-tmp")+",dst=/work/.tmp")
755		}
756		for _, tool := range tools {
757			if tool.Name == "" || tool.Path == "" {
758				continue
759			}
760			args = append(args, "--mount", "type=bind,src="+tool.Path+",dst=/usr/local/bin/"+tool.Name+",readonly")
761		}
762		for _, env := range dockerCredentialEnv() {
763			args = append(args, "-e", env)
764		}
765		tmpfsSize := "2g"
766		if cfg != nil && strings.TrimSpace(cfg.TmpfsSize) != "" {
767			tmpfsSize = strings.TrimSpace(cfg.TmpfsSize)
768		}
769		args = append(args, "--tmpfs", "/tmp:rw,nosuid,nodev,size="+tmpfsSize+",mode=1777")
770		if cfg != nil {
771			if cfg.Memory != "" {
772				args = append(args, "--memory", cfg.Memory)
773			}
774			if cfg.MemorySwap != "" {
775				args = append(args, "--memory-swap", cfg.MemorySwap)
776			}
777			if cfg.CPUs != "" {
778				args = append(args, "--cpus", cfg.CPUs)
779			}
780			if cfg.PidsLimit > 0 {
781				args = append(args, "--pids-limit", strconv.Itoa(cfg.PidsLimit))
782			}
783			if cfg.Network != "" {
784				args = append(args, "--network", cfg.Network)
785			}
786		}
787		return append(args, image)
788	}
