951		trimmed := bytes.TrimSpace(raw)
952		if len(trimmed) == 0 {
953			return nil, fmt.Errorf("docker-clone produced no JSON result")
954		}
955		start := bytes.IndexByte(trimmed, '{')
956		if start < 0 {
