package agent

import (
	"context"
	"os"
	"path/filepath"
	"testing"

	"github.com/stretchr/testify/require"
)

// TestIsolatedWorktree_FailedAttemptLeavesCanonicalRepoClean verifies that a
// failed execute-bead attempt removes the isolated worktree and leaves the
// canonical repo at the same HEAD with no uncommitted changes.
func TestIsolatedWorktree_FailedAttemptLeavesCanonicalRepoClean(t *testing.T) {
	projectRoot, _ := newScriptHarnessRepo(t, 1)
	baseRev := runGitInteg(t, projectRoot, "rev-parse", "HEAD")

	backend := WorktreeAttemptBackend{}
	gitOps := &RealGitOps{}

	ws, err := backend.Prepare(context.Background(), AttemptBackendPrepareRequest{
		ProjectRoot: projectRoot,
		BeadID:      "ddx-iso-0001",
		AttemptID:   "20260601T000000-aaaaaa00",
		BaseRev:     baseRev,
		GitOps:      gitOps,
	})
	require.NoError(t, err)
	require.DirExists(t, ws.WorkDir)

	// Simulate agent writes inside the isolated worktree.
	require.NoError(t, os.WriteFile(filepath.Join(ws.WorkDir, "agent-output.txt"), []byte("wip\n"), 0o644))

	// Cleanup mirrors the deferred call in ExecuteBeadWithConfig on failure.
	require.NoError(t, backend.Cleanup(context.Background(), ws))

	// Worktree is removed.
	require.NoDirExists(t, ws.WorkDir)

	// Canonical repo HEAD has not advanced.
	head, err := gitOps.HeadRev(projectRoot)
	require.NoError(t, err)
	require.Equal(t, baseRev, head)

	// Canonical repo has no uncommitted changes.
	dirty, err := gitOps.IsDirty(projectRoot)
	require.NoError(t, err)
	require.False(t, dirty, "canonical repo must not be dirty after failed attempt cleanup")
}

// TestIsolatedWorktree_RetryStartsFromCleanWorktree verifies that a retry
// (second Prepare after a failed Prepare+Cleanup) uses a separate worktree
// rooted at the same base rev, with no files from the prior attempt.
func TestIsolatedWorktree_RetryStartsFromCleanWorktree(t *testing.T) {
	projectRoot, _ := newScriptHarnessRepo(t, 1)
	baseRev := runGitInteg(t, projectRoot, "rev-parse", "HEAD")

	backend := WorktreeAttemptBackend{}
	gitOps := &RealGitOps{}

	// --- First attempt (fails) ---
	ws1, err := backend.Prepare(context.Background(), AttemptBackendPrepareRequest{
		ProjectRoot: projectRoot,
		BeadID:      "ddx-iso-0001",
		AttemptID:   "20260601T000000-aaaaaa00",
		BaseRev:     baseRev,
		GitOps:      gitOps,
	})
	require.NoError(t, err)
	require.NoError(t, os.WriteFile(filepath.Join(ws1.WorkDir, "attempt1.txt"), []byte("first attempt\n"), 0o644))
	require.NoError(t, backend.Cleanup(context.Background(), ws1))

	// --- Retry (second attempt) ---
	ws2, err := backend.Prepare(context.Background(), AttemptBackendPrepareRequest{
		ProjectRoot: projectRoot,
		BeadID:      "ddx-iso-0001",
		AttemptID:   "20260601T000001-bbbbbb01",
		BaseRev:     baseRev,
		GitOps:      gitOps,
	})
	require.NoError(t, err)
	t.Cleanup(func() { _ = backend.Cleanup(context.Background(), ws2) })

	// Retry uses a distinct worktree path.
	require.NotEqual(t, ws1.WorkDir, ws2.WorkDir)
	require.DirExists(t, ws2.WorkDir)

	// Retry worktree is checked out at the correct base rev.
	wtHead, err := gitOps.HeadRev(ws2.WorkDir)
	require.NoError(t, err)
	require.Equal(t, baseRev, wtHead)

	// Retry worktree has no files from the prior failed attempt.
	require.NoFileExists(t, filepath.Join(ws2.WorkDir, "attempt1.txt"))
}

