38	func (g *isolatedWorktreeGitOps) WorktreeAdd(dir, wtPath, rev string) error {
39		g.mu.Lock()
40		g.addedPaths = append(g.addedPaths, wtPath)
41		g.addedRevs = append(g.addedRevs, rev)
42		g.mu.Unlock()
43	
44		if err := os.MkdirAll(wtPath, 0o755); err != nil {
45			return err
46		}
47		ddxDir := filepath.Join(wtPath, ddxroot.DirName)
48		if err := os.MkdirAll(ddxDir, 0o755); err != nil {
49			return err
50		}
51		store := bead.NewStore(ddxDir)
52		if err := store.Init(); err != nil {
53			return err
54		}
55		return store.Create(&bead.Bead{ID: g.beadID, Title: "Isolated worktree test"})
56	}
