58	func (g *isolatedWorktreeGitOps) WorktreeRemove(dir, wtPath string) error {
59		g.mu.Lock()
60		g.removedPaths = append(g.removedPaths, wtPath)
61		g.mu.Unlock()
62		return os.RemoveAll(wtPath)
63	}
