65	func (g *isolatedWorktreeGitOps) WorktreeList(dir string) ([]string, error) {
66		g.mu.Lock()
67		defer g.mu.Unlock()
68		removed := make(map[string]bool, len(g.removedPaths))
69		for _, p := range g.removedPaths {
70			removed[p] = true
71		}
72		var active []string
73		for _, p := range g.addedPaths {
74			if !removed[p] {
75				active = append(active, p)
76			}
77		}
78		return active, nil
79	}
