117	// TestIsolatedWorktree_FailedAttemptLeavesCanonicalClean verifies that when an
118	// attempt fails (agent exits non-zero), the isolated worktree is removed so the
119	// canonical project root is left in a clean state with no dangling worktree
120	// directories.
121	func TestIsolatedWorktree_FailedAttemptLeavesCanonicalClean(t *testing.T) {
122		execRoot := setExecutionWorktreeRootForTest(t)
123		projectRoot := setupArtifactTestProjectRoot(t)
124		gitOps := newIsolatedWorktreeGitOps()
125	
126		res, err := runIsolatedWtAttempt(t, gitOps, projectRoot, 1)
127		if err != nil {
128			t.Fatalf("unexpected error from failed attempt: %v", err)
129		}
130		if res == nil {
131			t.Fatal("nil result from failed attempt")
132		}
133		if res.Outcome != ExecuteBeadOutcomeTaskFailed {
134			t.Errorf("outcome = %q, want %q", res.Outcome, ExecuteBeadOutcomeTaskFailed)
135		}
136	
137		// Exactly one worktree was created for the attempt.
138		if len(gitOps.addedPaths) != 1 {
139			t.Fatalf("WorktreeAdd calls = %d, want 1", len(gitOps.addedPaths))
140		}
141		wtPath := gitOps.addedPaths[0]
142	
143		// WorktreeRemove was called (deferred cleanup ran).
144		if len(gitOps.removedPaths) != 1 || gitOps.removedPaths[0] != wtPath {
145			t.Errorf("WorktreeRemove calls = %v, want [%s]", gitOps.removedPaths, wtPath)
146		}
147	
148		// The worktree directory must not exist on disk after cleanup.
149		if _, statErr := os.Stat(wtPath); !os.IsNotExist(statErr) {
150			t.Errorf("worktree %s still present on disk after failed attempt", wtPath)
151		}
152	
153		// No worktree dirs remain in the execution temp root.
154		entries, readErr := os.ReadDir(execRoot)
155		if readErr != nil {
156			t.Fatalf("reading execution root: %v", readErr)
157		}
158		for _, e := range entries {
159			if strings.HasPrefix(e.Name(), ExecuteBeadWtPrefix) {
160				t.Errorf("execution root has leftover worktree dir after failed attempt: %s", e.Name())
161			}
162		}
163	}
