165	// TestIsolatedWorktree_RetryStartsFromCleanWorktree verifies that after a
166	// failed attempt, a retry creates a fresh isolated worktree at the same base
167	// revision rather than inheriting any state from the failed attempt.
168	func TestIsolatedWorktree_RetryStartsFromCleanWorktree(t *testing.T) {
169		setExecutionWorktreeRootForTest(t)
170		projectRoot := setupArtifactTestProjectRoot(t)
171		gitOps := newIsolatedWorktreeGitOps()
172	
173		// First attempt fails.
174		res1, err1 := runIsolatedWtAttempt(t, gitOps, projectRoot, 1)
175		if err1 != nil || res1 == nil || res1.Outcome != ExecuteBeadOutcomeTaskFailed {
176			t.Fatalf("first attempt: want task_failed with nil error, got result=%v err=%v", res1, err1)
177		}
178		if len(gitOps.addedPaths) != 1 {
179			t.Fatalf("after first attempt: WorktreeAdd calls = %d, want 1", len(gitOps.addedPaths))
180		}
181		firstWtPath := gitOps.addedPaths[0]
182	
183		// The first worktree is cleaned up before the retry.
184		if _, err := os.Stat(firstWtPath); !os.IsNotExist(err) {
185			t.Errorf("first worktree %s not cleaned up before retry", firstWtPath)
186		}
187	
188		// Second attempt (retry).
189		res2, err2 := runIsolatedWtAttempt(t, gitOps, projectRoot, 1)
190		if err2 != nil || res2 == nil || res2.Outcome != ExecuteBeadOutcomeTaskFailed {
191			t.Fatalf("second attempt: want task_failed with nil error, got result=%v err=%v", res2, err2)
192		}
193	
194		// Two distinct worktree paths — one per attempt.
195		if len(gitOps.addedPaths) != 2 {
196			t.Fatalf("WorktreeAdd calls = %d, want 2", len(gitOps.addedPaths))
197		}
198		secondWtPath := gitOps.addedPaths[1]
199		if firstWtPath == secondWtPath {
200			t.Errorf("retry reused worktree path %q; want a fresh isolated worktree", firstWtPath)
201		}
202	
203		// Each worktree was created at the same clean base revision.
204		for i, rev := range gitOps.addedRevs {
205			if rev != isolatedWtBaseRev {
206				t.Errorf("worktree[%d] created at rev %q, want %q", i, rev, isolatedWtBaseRev)
207			}
208		}
209	
210		// Both worktrees were cleaned up after their respective attempts.
211		if len(gitOps.removedPaths) != 2 {
212			t.Fatalf("WorktreeRemove calls = %d, want 2; remaining=%v", len(gitOps.removedPaths), gitOps.removedPaths)
213		}
214		if _, err := os.Stat(firstWtPath); !os.IsNotExist(err) {
215			t.Errorf("first worktree %s still exists after retry", firstWtPath)
216		}
217		if _, err := os.Stat(secondWtPath); !os.IsNotExist(err) {
218			t.Errorf("second worktree %s still exists after retry", secondWtPath)
219		}
220	}
